  "verses": [
    {
      "n": 9,
      "column": "left",
      "text": "Vahr teem Praweescheein.\nManna Sirds tohp manna\nWiddû lausita / wiſſi manni\nKauli drebb/ es efnuu ka weens\npeedſehris Wihrs/ un ka weens/\nfo tas Wihrs pahrwarre / ta\nKUNGA Preeſchá/ un preekſch\nteem Wahrdeem winna Sweh-\ntibas."
    },
    {
      "n": 10,
      "column": "left",
      "text": "Jo ta Semme irr piſna\nLaulibas-Pahrkahpaju / jo ta\nSemme behdajahs to Lahstu\ndeht/ tahs Tuksnefes Gannibas\niſkalſt/ tadeht ka winno Bah-\nſhana tauna irraid/ un winno\nWaldischana ne irr pareiſt."
    },
    {
      "n": 11,
      "column": "left",
      "text": "Jo tik labbi tas Praweets\nka Preesteris irr apblehnoju-\nſchees / patt manna Namma\natrohnii es winno Blehdibu /\nfakka tas KUNGS:"
    },
    {
      "n": 12,
      "column": "left",
      "text": "Tapehz buhs winnu Zefsch\nka fliddenas Weetas Tumsiba /\npee ka tee peedausifees un krit-\ntihs. Jo es weddifchu pahr teem\nLaununu winnu Beemekletcha-\nnas Gaddá/ fakka tas KUNGS."
    },
    {
      "n": 13,
      "column": "left",
      "text": "Gann es pee teent Pra-\nweescheem eekſch Samarijas re-\nDfeju aplamas Leetas/ jo tee flud-\ndinaja zaar Baálu/ un peewihle\nmannus Israêta Landis."
    },
    {
      "n": 14,
      "column": "left",
      "text": "Bet pee teem Prawee-\nſcheem eekſch Jerusalemes redsu\nes Negantibu/ tee pahrkahpj to\nLaulibu / un tinnabs ar Wilți-\nbu/ un ſtiprina to Launadarri-"
    },
    {
      "n": 15,
      "column": "right",
      "text": "Tapehz fakka tas KUNGS\nZebaot no ſcheim Praweescheem\nta: Rangi/ es ehdiſachhu tohs\nar Wehrmelehin/un dsirdinaſchu\ntohs ar Schulta Uhdeni/ jo no\nteem Jerusalemes Praweescheem\nirr ta Blehdiba iſgahjuti wiſſá\nSemmê."
    },
    {
      "n": 16,
      "column": "right",
      "text": "Ta fakka tas KUNGS\nZebaot: Ne klaufajt to Prawee-\nſchu Wahrdeem/ kas jums flud-\ndina/ tee darra juhs neleeſchus/\ntee runna fawas Sirds Parah-\nditchanu / ue no ta KUNGA\nMuttes."
    },
    {
      "n": 17,
      "column": "right",
      "text": "Tee fakka allaschix uhs\nteem/ kas manni ſaimo : Tas\nKUNGS irr to runnajs / ka\njums Meers buhs/ un uhs wiſ-\nſeem / kas pehz ſawa Strde\nPrahta staiga / fakka tee: Pah-\njums ne nahks Launuuns."
    },
    {
      "n": 18,
      "column": "right",
      "text": "Jo kas irr eekſch ta KUN-\nGA Padohina stahwejs ? un\nwinna Wahrdü redſejs jeb dſir-\ndejs? Kas irr winna Wahrdü\nwehra iehmis un klaufijs?"
    },
    {
      "n": 19,
      "column": "right",
      "text": "Rangi / ta KUNGA\nWehtra zelſees ar Bahrsibu/ ir-\nweena pastahwiga Wehtra/ ta\nkrittihs us to Besdeewigo Gal-\nwu."
    },
    {
      "n": 20,
      "column": "right",
      "text": "Ta KUNGA Bahrsiba\nne greesifees atpakkat / teekam-\nta irr darriſfi/ un tamehr ta ir-\neezech"
    }
  ],
  "confidence": "high",
  "notes": ""
}
